    def visit_Set(self, node: ast.Set) -> Any:
        raise _UnsafeExpression("Sets are not allowed")

    def visit_Lambda(self, node: ast.Lambda) -> Any:
        raise _UnsafeExpression("Lambdas are not allowed")

    def visit_IfExp(self, node: ast.IfExp) -> Any:
        raise _UnsafeExpression("Conditional expressions are not allowed")

    def visit_Compare(self, node: ast.Compare) -> Any:
        raise _UnsafeExpression("Comparisons are not allowed")

    def visit_BoolOp(self, node: ast.BoolOp) -> Any:
        raise _UnsafeExpression("Boolean operations are not allowed")

    def visit_BitAnd(self, node: ast.BitAnd) -> Any:
        raise _UnsafeExpression("Bitwise operations are not allowed")

    def visit_BitOr(self, node: ast.BitOr) -> Any:
        raise _UnsafeExpression("Bitwise operations are not allowed")

    def visit_BitXor(self, node: ast.BitXor) -> Any:
        raise _UnsafeExpression("Bitwise operations are not allowed")

    def visit_Invert(self, node: ast.Invert) -> Any:
        raise _UnsafeExpression("Bitwise operations are not allowed")

    def visit_NameConstant(self, node: ast.NameConstant) -> Any:  # Py<3.8
        raise _UnsafeExpression("Only numeric constants are allowed")

    def visit_Str(self, node: ast.Str) -> Any:  # Py<3.8
        raise _UnsafeExpression("Strings are not allowed")

    def visit_Bytes(self, node: ast.Bytes) -> Any:  # Py<3.8
        raise _UnsafeExpression("Bytes are not allowed")

    def visit_JoinedStr(self, node: ast.JoinedStr) -> Any:
        raise _UnsafeExpression("f-strings are not allowed")

    def visit_FormattedValue(self, node: ast.FormattedValue) -> Any:
        raise _UnsafeExpression("Formatted values are not allowed")


def validate_math_expression(expr_string: str) -> str:
    """
    Pure function that validates the raw input string for a mathematical expression.
    Returns the normalized (stripped) expression if valid; raises _UnsafeExpression otherwise.
    """
    if not isinstance(expr_string, str):
        raise _UnsafeExpression("Expression must be a string")

    expr = expr_string.strip()
    if not expr:
        raise _UnsafeExpression("Empty expression")

    # Fast reject of obviously unsafe characters (heuristic)
    # Disallow semicolons, newlines, equals, braces, brackets, and colons which are not needed in pure math expr
    if any(ch in expr for ch in (";", "\n", "\r", "=", "{", "}", "[", "]", ":")):
        raise _UnsafeExpression("Disallowed characters present")

    return expr


def evaluate_math_expression(expr: str) -> float:
    """
    Pure function that parses and safely evaluates a validated mathematical expression.
    Returns a numeric result; raises _UnsafeExpression on any disallowed construct or failure.
    """
    try:
        tree = ast.parse(expr, mode="eval")
    except Exception as exc:
        # Parsing failure
        raise _UnsafeExpression("Parse error") from exc

    evaluator = _SafeMathEvaluator()
    result = evaluator.visit(tree)

    if not isinstance(result, (int, float)) or isinstance(result, bool):
        raise _UnsafeExpression("Non-numeric result")

    return result


def _preview(text: Any, max_len: int = 200) -> str:
    """
    Create a safe, shortened preview for logging.
    """
    try:
        s = str(text)
    except Exception:
        s = repr(text)
    s = s.replace("\n", "\\n").replace("\r", "\\r")
    if len(s) > max_len:
        return f"{s[:max_len]}...(truncated {len(s) - max_len} chars)"
    return s


def safe_math_evaluator(expr_string: str) -> str:
    """
    Safely evaluates a mathematical Python expression and returns its result as a string.
    Returns 'Unsafe Code Detected!' if the input contains disallowed constructs or evaluation fails.
    """
    req_id = uuid.uuid4().hex
    expr_preview = _preview(expr_string)

    logger.info("Evaluation start | id=%s | expr=%s", req_id, expr_preview)

    try:
        normalized = validate_math_expression(expr_string)
        if normalized != expr_string:
            logger.debug("Expression normalized | id=%s | normalized=%s", req_id, _preview(normalized))

        result = evaluate_math_expression(normalized)
        logger.info("Evaluation success | id=%s | result=%s", req_id, _preview(result))
        return str(result)
    except _UnsafeExpression as ue:
        logger.warning(
            "Unsafe expression detected | id=%s | reason=%s | expr=%s",
            req_id,
            _preview(ue),
            expr_preview,
        )
        return "Unsafe Code Detected!"
    except Exception:
        logger.exception("Evaluation error | id=%s | expr=%s", req_id, expr_preview)
        return "Unsafe Code Detected!"
